-- Suggested indexes / unique constraints
-- Prevent duplicate run-level vessel rows and speed active dataset reads.
-- CREATE INDEX IF NOT EXISTS idx_vessel_snapshots_run_id_master_vessel_id ON public.vessel_snapshots (run_id, master_vessel_id);
-- Current target ordering should be unique per run.
-- CREATE INDEX IF NOT EXISTS idx_sales_candidates_current_run_id_rank ON public.sales_candidates_current (run_id, rank);
-- Immediate target ordering should be unique per run.
-- CREATE INDEX IF NOT EXISTS idx_immediate_targets_current_run_id_rank ON public.immediate_targets_current (run_id, rank);
-- One current summary per port per run.
-- CREATE INDEX IF NOT EXISTS idx_port_summary_current_run_id_port_code ON public.port_summary_current (run_id, port_code);
-- Reduce repeated pending recovery candidates.
-- CREATE INDEX IF NOT EXISTS idx_imo_recovery_queue_run_id_call_sign_vessel_name ON public.imo_recovery_queue (run_id, call_sign, vessel_name);
-- Canonical IMO lookup; use partial unique index where IMO is not null.
-- CREATE INDEX IF NOT EXISTS idx_vessel_master_imo ON public.vessel_master (imo);
-- Canonical MMSI lookup; use partial unique index where MMSI is not null.
-- CREATE INDEX IF NOT EXISTS idx_vessel_master_mmsi ON public.vessel_master (mmsi);

